const listA11OutboxAfter = `-- name: ListA11OutboxAfter :many
SELECT revision, id, topic, payload_hash, created_at, published_at, stream, schema_version, entity_type, entity_id, entity_revision, event_time, correlation_id, causation_id, payload FROM outbox_events WHERE revision>$1 ORDER BY revision LIMIT $2
`

type ListA11OutboxAfterParams struct {
	Revision int64 `db:"revision" json:"revision"`
	Limit    int32 `db:"limit" json:"limit"`
}

func (q *Queries) ListA11OutboxAfter(ctx context.Context, arg ListA11OutboxAfterParams) ([]*OutboxEvent, error) {
	rows, err := q.db.Query(ctx, listA11OutboxAfter, arg.Revision, arg.Limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []*OutboxEvent{}
	for rows.Next() {
		var i OutboxEvent
		if err := rows.Scan(
			&i.Revision,
			&i.ID,
			&i.Topic,
			&i.PayloadHash,
			&i.CreatedAt,
			&i.PublishedAt,
			&i.Stream,
			&i.SchemaVersion,
			&i.EntityType,
			&i.EntityID,
			&i.EntityRevision,
			&i.EventTime,
			&i.CorrelationID,
			&i.CausationID,
			&i.Payload,
		); err != nil {
			return nil, err
		}
		items = append(items, &i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const oldestA11OutboxRevision = `-- name: OldestA11OutboxRevision :one
SELECT coalesce(min(candidate.revision),0)::bigint FROM outbox_events AS candidate
WHERE candidate.created_at >= $1 OR candidate.revision >
  (SELECT greatest(coalesce(max(current.revision),0)-100000,0) FROM outbox_events AS current)
`

func (q *Queries) OldestA11OutboxRevision(ctx context.Context, retainedAfter pgtype.Timestamptz) (int64, error) {
	row := q.db.QueryRow(ctx, oldestA11OutboxRevision, retainedAfter)
	var column_1 int64
	err := row.Scan(&column_1)
	return column_1, err
}

